/**
 * Create insert/update/delete triggers that keep an FTS5 table
 * in sync with its content table.
 */
function createSyncTriggers(db: Database, table: string, ftsTable: string, columns: string[]): void {
  const newCols = columns.map((c) => `new.${c}`).join(", ");
  const oldCols = columns.map((c) => `old.${c}`).join(", ");
  const colList = columns.join(", ");
  // Quote table name — "references" is a SQLite reserved word
  const qt = `"${table}"`;

  // After INSERT
  db.exec(`
    CREATE TRIGGER IF NOT EXISTS ${table}_ai AFTER INSERT ON ${qt} BEGIN
      INSERT INTO ${ftsTable}(rowid, ${colList})
      VALUES (new.id, ${newCols});
    END;
  `);

  // After DELETE
  db.exec(`
    CREATE TRIGGER IF NOT EXISTS ${table}_ad AFTER DELETE ON ${qt} BEGIN
      INSERT INTO ${ftsTable}(${ftsTable}, rowid, ${colList})
      VALUES ('delete', old.id, ${oldCols});
    END;
  `);

