// ── Private: stage a proposal with appropriate logging ───────────────────────

async function _stageProposal(
  agent: string,
  proposal: ParsedProposal,
  gateResults: AllGatesResult,
  judgeResults: JudgePanelResult | null,
  reason: string,
): Promise<void> {
  const today = dayjs().format("YYYY-MM-DD");

  // Bridge gates.ts AllGatesResult → staged.ts AllGatesResult format
  const stagedGateResults = {
    passed: gateResults.passed,
    gates: gateResults.results.map(r => ({
      gate: r.gate,
      passed: r.pass,
      reason: r.reason,
    })),
  };

  // Bridge judge-panel.ts JudgePanelResult → staged.ts JudgePanelResult format
  const stagedJudgeResults = judgeResults
    ? {
        approved: judgeResults.approved,
        votes: judgeResults.votes.map(v => ({
          judge: v.model,
          approved: v.vote === "approve",
          reasoning: v.reason,
        })),
      }
    : null;

  const stagedProposal: StagedProposal = {
    agent,
    date: today,
    proposedChange: proposal.title,
    section: proposal.section,
    changeType: proposal.type,
    evidence: proposal.evidence,
    gateResults: stagedGateResults as any,
    judgeResults: stagedJudgeResults as any,
    reason,
    status: "pending",
  };

  try {
    writeStagedProposal(stagedProposal);
  } catch {
    // Stage write failure is non-fatal — pipeline continues
  }

  // Log to brain.db
  const linesAdded = countLines(proposal.content, proposal.type === "add");
  const linesRemoved = countLines(proposal.content, proposal.type === "remove");

  try {
    logSoulChange({
      agent,
      date: today,
      linesAdded,
      linesRemoved,
      changeSummary: `[staged] ${proposal.title}: ${reason.slice(0, 200)}`,
      gateResults: JSON.stringify(stagedGateResults),
      judgeResults: judgeResults ? JSON.stringify(stagedJudgeResults) : undefined,
      status: "staged",
    });

