  // ── Run Gemini ──────────────────────────────────────────────────────────

  const out: string[] = [];
  out.push(`=== SOUL DISTILLATION: ${agent} ===`);
  out.push(`  Soul: ${soulPath}`);
  out.push(`  Knowledge: ${agentKnowledge ? "yes" : "none"} (agent), ${sharedKnowledge ? "yes" : "none"} (shared)`);
  out.push("");
  out.push("Analyzing knowledge against soul...");

  let output: string;
  try {
    const result = await generateText(prompt, {
      model: "gemini-2.5-flash",
      timeout: 120_000,
      maxOutputTokens: 16384,
      temperature: 0.3,
      caller: "distill-soul",
    });
    output = result.text;
    if (result.inputTokens || result.outputTokens) {
      out.push(`  Gemini: ${result.inputTokens ?? "?"} in / ${result.outputTokens ?? "?"} out tokens`);
    }
  } catch (err: any) {
    throw new Error(`Gemini failed: ${err.message?.split("\n")[0] || "unknown"}`);
  }

  // ── Parse output ────────────────────────────────────────────────────────

  if (output.includes("NO_CHANGES")) {
    out.push("");
    out.push("No knowledge qualifies for soul promotion yet.");
    out.push("Keep running workflows — learnings need to be proven before they enter the soul.");
    return out.join("\n");
  }

  // Extract summary
  const summaryMatch = output.match(/SUMMARY:\n([\s\S]*?)(?=\nPROPOSALS:)/);
  if (summaryMatch) {
    out.push("");
    out.push("--- SUMMARY ---");
    out.push(summaryMatch[1].trim());
    out.push("--- END SUMMARY ---");
  }

  // Extract proposals
  const proposalRegex = /===\s*PROPOSAL\s*\d+:\s*(.*?)\s*===\n([\s\S]*?)===\s*END PROPOSAL\s*===/g;
  const proposals: { title: string; body: string }[] = [];
  let match;
  while ((match = proposalRegex.exec(output)) !== null) {
    proposals.push({ title: match[1].trim(), body: match[2].trim() });
  }

  if (proposals.length > 0) {
    out.push("");
    out.push(`${proposals.length} proposal(s):`);
    out.push("");
    for (let i = 0; i < proposals.length; i++) {
      out.push(`  ${i + 1}. ${proposals[i].title}`);
      // Show first few lines of each proposal
      const lines = proposals[i].body.split("\n");
      for (const line of lines.slice(0, 6)) {
        out.push(`     ${line}`);
      }
      if (lines.length > 6) out.push(`     ... (${lines.length - 6} more lines)`);
      out.push("");
    }
  }

  // Extract full soul
  const fullSoulMatch = output.match(/FULL_SOUL:\n([\s\S]*?)$/);
  const newSoulContent = fullSoulMatch
    ? fullSoulMatch[1].replace(/^```markdown?\n?/, "").replace(/```\s*$/, "").trim()
    : null;

  // ── Apply or dry-run ────────────────────────────────────────────────────

  if (!apply) {
    out.push("--- MODE: DRY RUN ---");
    out.push("Review the proposals above. To apply:");
    out.push(`  bun src/tools/distill-soul.ts --agent ${agent} --apply`);
    out.push("");

    if (newSoulContent) {
      out.push("--- PROPOSED SOUL FILE ---");
      out.push(newSoulContent);
      out.push("--- END ---");
    }

    return out.join("\n");
  }

  // Apply mode
  if (!newSoulContent) {
    throw new Error("Could not extract the full soul content from Gemini output. Run with --dry-run to see the raw output.");
  }

  writeFileSync(soulPath, newSoulContent + "\n", "utf-8");
  out.push("");
  out.push(`Soul file updated: ${soulPath}`);
  out.push(`${proposals.length} proposal(s) applied.`);

