#!/usr/bin/env bun
/**
 * distill-soul.ts — Propose soul file updates from accumulated knowledge
 *
 * Dual-mode: CLI (`bun src/tools/distill-soul.ts --agent tala`) or native tool via registry.
 *
 * Reads an agent's knowledge/ files and current soul file, identifies
 * proven and fundamental learnings, and proposes a diff. User approves
 * before anything is written to the soul.
 *
 * Usage:
 *   bun src/tools/distill-soul.ts --agent tala
 *   bun src/tools/distill-soul.ts --agent tala --dry-run
 *   bun src/tools/distill-soul.ts --agent tala --apply
 *
 * Options:
 *   --agent    Agent name (tala, rune, sol, echo, penny)
 *   --dry-run  Show proposal without writing (default)
 *   --apply    Write approved changes to soul file
 */

import { existsSync, readFileSync, readdirSync, writeFileSync } from "fs";
import { join } from "path";
import { generateText } from "../libs/gemini.js";
import { fromRoot } from "../libs/paths.js";
import { z } from "zod";
import type { ToolDefinition } from "../registry/types.js";

// ── Paths ───────────────────────────────────────────────────────────────────

const memoryRoot = fromRoot("vault", "studio", "memory");
const soulsDir = fromRoot(".claude", "souls");

const AGENTS = ["tala", "rune", "sol", "echo", "penny"];

// ── Helpers ─────────────────────────────────────────────────────────────────

function loadDir(dir: string): string {
  if (!existsSync(dir)) return "";
  const files = readdirSync(dir).filter(f => f.endsWith(".md"));
  if (files.length === 0) return "";
  return files
    .map(f => `### ${f}\n${readFileSync(join(dir, f), "utf-8")}`)
    .join("\n\n");
