    // distillSoul is not exported from distill-soul.ts — use toolDef.execute (dry-run mode)
    const toolModule = await import("../tools/distill-soul.js");
    const result = await toolModule.toolDef.execute({ agent, apply: false });
    if (result.isError) {
      throw new Error(result.output as string);
    }
    distillOutput = result.output as string;
  } catch (err: any) {
    agentResults.push({
      agent,
      skipped: false,
      proposals: [],
      error: `distillSoul failed: ${err.message?.split("\n")[0] ?? "unknown"}`,
    });
    continue;
  }

  // Check for skip signals in output
  if (
    distillOutput.includes("No knowledge files found") ||
    distillOutput.includes("Nothing to distill")
  ) {
    agentResults.push({
      agent,
      skipped: true,
      skipReason: "No knowledge files found",
      proposals: [],
    });
    continue;
  }

