/**
 * gates.ts — Validation gates for soul file changes
 *
 * 5 gates run in order (cheapest first):
 *   1. safety    — deterministic: block changes to protected sections
<<<<<<< HEAD
 *   2. size      — deterministic: max 3 added/modified lines, 1 removed
=======
 *   2. size      — deterministic: max 6 added lines, 1 removed, 0 modified
>>>>>>> 553e0d6 (Constrain distill-soul proposals to 6 lines and bump Gate 2 size limit to 6)
 *   3. drift     — deterministic: DB query, cumulative 30-day change limit
 *   4. regression — embeddings + optional Gemini: contradiction detection
 *   5. constitution — Gemini LLM call: identity alignment check
 *
 * All 5 gates always run (no short-circuit) — full results for human review.
 */

import { generateText } from "./gemini.js";
import { embedText, embedBatch } from "./embeddings.js";
import { querySoulDrift } from "./brain/queries.js";

// ── Types ────────────────────────────────────────────────────────────────────

export interface GateResult {
  gate: string;   // "constitution" | "regression" | "size" | "drift" | "safety"
  pass: boolean;
  reason: string;
}

export interface GateInput {
  agent: string;
  currentSoul: string;
  proposedDiff: ProposedChange[];
}

export interface ProposedChange {
  type: "add" | "remove" | "modify";
  section: string;
  content: string;
  evidence: string;
}

export interface AllGatesResult {
  passed: boolean;
  results: GateResult[];
  failedGates: string[];
}

// ── Protected section names (case-insensitive) ──────────────────────────────

const PROTECTED_SECTION_NAMES = [
  "who i am",
  "who you are",
  "creative philosophy",
  "hard rules",
  "the line i won't cross",
  "my line",
  "core identity",
];

// ── Helper: cosine similarity ────────────────────────────────────────────────

export function cosineSimilarity(a: number[], b: number[]): number {
  if (a.length === 0 || b.length === 0 || a.length !== b.length) return 0;
  let dot = 0;
  let magA = 0;
  let magB = 0;
  for (let i = 0; i < a.length; i++) {
    dot += a[i] * b[i];
    magA += a[i] * a[i];
    magB += b[i] * b[i];
  }
  const denom = Math.sqrt(magA) * Math.sqrt(magB);
  return denom === 0 ? 0 : dot / denom;
}

// ── Helper: parse protected sections from soul text ──────────────────────────

/**
 * Returns a Set of lowercase section names that are protected.
 * Protected = named in PROTECTED_SECTION_NAMES or contains <!-- protected -->.
 */
function parseProtectedSections(soulText: string): Set<string> {
  const protected_ = new Set<string>();
  const lines = soulText.split("\n");
  let currentSection = "";
  let sectionLines: string[] = [];

  function flushSection() {
    if (!currentSection) return;
    const nameLower = currentSection.toLowerCase();
    if (PROTECTED_SECTION_NAMES.includes(nameLower)) {
      protected_.add(nameLower);
    } else if (sectionLines.some(l => l.includes("<!-- protected -->"))) {
      protected_.add(nameLower);
    }
  }

  for (const line of lines) {
    const headingMatch = line.match(/^#{1,6}\s+(.+)$/);
    if (headingMatch) {
      flushSection();
      currentSection = headingMatch[1].trim();
      sectionLines = [];
    } else {
      sectionLines.push(line);
    }
  }
  flushSection();

  return protected_;
}

// ── Helper: extract rule-like sentences from soul text ──────────────────────

/**
 * Returns lines that look like rules: list items, lines with modal verbs,
 * or lines inside Hard Rules / Core Opinions / Postmortem Reflexes sections.
 */
function extractRuleSentences(soulText: string): string[] {
  const rules: string[] = [];
  const lines = soulText.split("\n");
  const ruleHeaders = ["hard rules", "core opinions", "postmortem reflexes"];
  let inRuleSection = false;

  for (const line of lines) {
    const trimmed = line.trim();
    if (!trimmed) continue;

    // Check for section heading
    const headingMatch = trimmed.match(/^#{1,6}\s+(.+)$/);
    if (headingMatch) {
      inRuleSection = ruleHeaders.includes(headingMatch[1].toLowerCase());
      continue;
    }

    // Collect from rule sections unconditionally
    if (inRuleSection) {
      rules.push(trimmed);
      continue;
    }

    // List items (-, *, numbered)
    if (/^[-*]\s+.+/.test(trimmed) || /^\d+\.\s+.+/.test(trimmed)) {
      rules.push(trimmed);
      continue;
    }

    // Lines with modal verbs
    if (/\b(always|never|must|don't|do not)\b/i.test(trimmed)) {
      rules.push(trimmed);
      continue;
    }
  }

  return rules;
}

// ── Gate 1: Safety ───────────────────────────────────────────────────────────

/**
 * Gate 1 (cheapest): Block any changes targeting protected sections.
 * Fully deterministic — no LLM, no DB.
 */
async function runSafetyGate(input: GateInput): Promise<GateResult> {
  if (!input.currentSoul || typeof input.currentSoul !== "string") {
    return { gate: "safety", pass: false, reason: "currentSoul is empty or invalid" };
  }
  if (!input.proposedDiff || input.proposedDiff.length === 0) {
    return { gate: "safety", pass: true, reason: "No proposed changes — nothing to check" };
  }

  const protected_ = parseProtectedSections(input.currentSoul);
  if (protected_.size === 0) {
    return { gate: "safety", pass: true, reason: "No protected sections found in soul file" };
  }

  const violations: string[] = [];
  for (const change of input.proposedDiff) {
    const sectionLower = (change.section ?? "").toLowerCase().trim();
    if (protected_.has(sectionLower)) {
      violations.push(`"${change.section}" is a protected section`);
    }
  }

  if (violations.length > 0) {
    return {
      gate: "safety",
      pass: false,
      reason: `Changes target protected sections: ${violations.join("; ")}`,
    };
  }

  return { gate: "safety", pass: true, reason: "No changes target protected sections" };
}

// ── Gate 2: Size ─────────────────────────────────────────────────────────────

/**
 * Gate 2: Enforce per-cycle line budget.
