  // Unwrap settled results — a gate rejection counts as a fail
  function unwrap(settled: PromiseSettledResult<GateResult>, gateName: string): GateResult {
    if (settled.status === "fulfilled") return settled.value;
    return {
      gate: gateName,
      pass: false,
      reason: `Gate threw unexpectedly: ${settled.reason?.message ?? settled.reason}`,
    };
  }

  const results: GateResult[] = [
    unwrap(safety, "safety"),
    unwrap(size, "size"),
    unwrap(drift, "drift"),
    unwrap(regression, "regression"),
    unwrap(constitution, "constitution"),
  ];

  const failedGates = results.filter(r => !r.pass).map(r => r.gate);

  return {
    passed: failedGates.length === 0,
    results,
    failedGates,
  };
}

