 * Chat completion via MiniMax API.
 */
export async function chatCompletion(config: ChatConfig): Promise<ChatResult> {
  const apiKey = getApiKey();
  const model = config.model ?? "MiniMax-M2.7";

  const response = await fetch(`${API_BASE}/text/chatcompletion_v2`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "Authorization": `Bearer ${apiKey}`,
    },
    body: JSON.stringify({
      model,
      messages: config.messages,
      temperature: config.temperature ?? 0.7,
      max_tokens: config.maxTokens ?? 4096,
    }),
  });

  if (!response.ok) {
    throw new Error(`MiniMax API error: HTTP ${response.status} ${response.statusText}`);
  }

  const json = await response.json() as any;

  if (json.base_resp?.status_code && json.base_resp.status_code !== 0) {
    const code = json.base_resp.status_code;
    const msg = ERROR_CODES[code] || json.base_resp.status_msg || `Error code ${code}`;
    throw new Error(`MiniMax error: ${msg}`);
  }

  const choice = json.choices?.[0];
  const text = choice?.message?.content ?? "";
  const usage = json.usage || {};
  const inputTokens = usage.prompt_tokens ?? 0;
  const outputTokens = usage.completion_tokens ?? 0;

  const costUsd = (inputTokens / 1_000_000) * 0.30 + (outputTokens / 1_000_000) * 1.20;

  // Track usage
  try {
    trackUsage({
      provider: "minimax",
      model,
      caller: config.caller ?? "minimax-chat",
      inputTokens,
      outputTokens,
      costUsd: Math.round(costUsd * 1_000_000) / 1_000_000,
    });
  } catch {}

  return {
    text,
    model,
    inputTokens,
    outputTokens,
    costUsd: Math.round(costUsd * 1_000_000) / 1_000_000,
  };
}

