/**
 * Get recent soul change records.
 *
 * @param agent - Optional agent filter
 * @param opts.limit - Max rows to return (default 20)
 * @param opts.since - Optional ISO date string lower bound on created_at
 */
export function getRecentSoulChanges(
  agent?: string,
  opts?: { limit?: number; since?: string },
): SoulChangeRecord[] {
  const raw = getRawDb();
  const limit = opts?.limit ?? 20;

  let sqlStr = `SELECT id, agent, date, lines_added, lines_removed, change_summary,
                       gate_results, judge_results, status, created_at
                FROM soul_changes WHERE 1=1`;
  const params: any[] = [];

  if (agent) {
    sqlStr += " AND agent = ?";
    params.push(agent);
  }
  if (opts?.since) {
    sqlStr += " AND created_at >= ?";
    params.push(opts.since);
  }

  sqlStr += " ORDER BY created_at DESC LIMIT ?";
  params.push(limit);

  const rows = raw.prepare(sqlStr).all(...params) as any[];
  return rows.map((r) => ({
    id: r.id,
    agent: r.agent,
    date: r.date,
    linesAdded: r.lines_added,
    linesRemoved: r.lines_removed,
    changeSummary: r.change_summary,
    gateResults: r.gate_results,
    judgeResults: r.judge_results,
    status: r.status,
    createdAt: r.created_at,
  }));
}

